#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=205,base=31;
int n,kk,ss,siz[N],num[N][N],dp[N][55],vis[N];
unsigned ll has[N],has2[15][N],tmp[N];
string s=" ",s2;
unsigned ll fun(int l,int r,unsigned ll a[])
{
    return a[r]-a[l-1]*tmp[r-l+1];
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
//    freopen(".in","r",stdin);
//    freopen(".out","w",stdout);
    cin>>n>>kk;
    for(int i=1;i<=n;i++)
    {
        cin>>s2;
        s+=s2;
    }
    n=s.size()-1;
    tmp[0]=1;
    for(int i=1;i<s.size();i++)
    {
        has[i]=(has[i-1]*base+s[i]-'a');
        tmp[i]=tmp[i-1]*base;
//        cout<<has[i]<<" ";
    }
//    cout<<"\n";
    cin>>ss;
    for(int i=1;i<=ss;i++)
    {
        cin>>s2;
        siz[i]=s2.size();
        s2=" "+s2;
//        cout<<"bbb  ";
        for(int j=1;j<s2.size();j++)
        {
            has2[i][j]=has2[i][j-1]*base+s2[j]-'a';
//            cout<<has2[i][j]<<" ";
        }
//        cout<<"\n";
    }
    for(int i=1;i<=n;i++)
    {
        memset(vis,0,sizeof(vis));
        for(int j=i;j<=n;j++)
        {
            num[i][j]=num[i][j-1];
            for(int k=1;k<=ss;k++)
            {
                int tt=j-siz[k]+1;
//                cout<<i<<" "<<j<<" "<<k<<" "<<tt<<"\n";
//                if((tt>=i)&&(vis[tt]==0)) cout<<"a\n";
//				if((tt>=i)&&(vis[tt]==0)) cout<<i<<" "<<j<<" "<<k<<"  hash1: "<<fun(tt,j,has)<<" hash2: "<<fun(1,siz[k],has2[k])<<"\n";
                if((tt>=i)&&(vis[tt]==0)&&(fun(tt,j,has)==fun(1,siz[k],has2[k])))
                {
//                	cout<<i<<" "<<j<<" "<<k<<"\n";
                    num[i][j]++;
                    vis[tt]=1;
                }
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=min(kk,i);j++)
        {
            for(int k=j;k<=i;k++)
            {
                dp[i][j]=max(dp[i][j],dp[k-1][j-1]+num[k][i]);
//                cout << i << " " << j << "\n";
            }
        }
    }
//    cout << "n= "<< n << "; kk=" << kk << "\n";
    cout<<dp[n][kk];
    return 0;
}
